import{_ as a,c as o,o as t,aj as d}from"./chunks/framework.CjkNaYQl.js";const u=JSON.parse('{"title":"2. 軟體精熟篇","description":"","frontmatter":{},"headers":[],"relativePath":"intermediate/2.md","filePath":"intermediate/2.md"}'),c={name:"intermediate/2.md"};function i(l,e,r,n,s,h){return t(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="_2-軟體精熟篇" tabindex="-1">2. 軟體精熟篇 <a class="header-anchor" href="#_2-軟體精熟篇" aria-label="Permalink to &quot;2. 軟體精熟篇&quot;">​</a></h1><p>相信大家藉由基階課程中都已經學到軟體的基本操作方式了，因此在這篇中階教材中，我們將會以更快的速度來說明更多比賽必備的操作，要是能把這些東西都玩熟，一定能在初賽中取得好成績！</p><h2 id="變數" tabindex="-1">變數 <a class="header-anchor" href="#變數" aria-label="Permalink to &quot;變數&quot;">​</a></h2><p>要在專案中建立變數，要先到畫面上方 <code>管理員</code> → <code>變數</code> 來開啟變數管理的頁面，要注意，我們所有建立的變數都只會用到 <code>專案變數</code>，小心不要建立到 <code>全域變數</code> 而造成命名污染。</p><p>我們在 <code>專案變數</code> → <code>變數</code> 畫面，就可以建立一個變數了，變數型別有很多，可以在 <code>型別</code> 的下拉選單中，選擇一種資料類型，相信這些東西對於會寫程式的人來說再熟悉不過了，但若沒學過程式的人也不要緊張，我們在大多數情況下，變數都只是為了計數，因此直接選擇 <code>int</code>（整數）即可。<code>名稱</code> 同樣也要遵守稱式中變數命名規則，即只用<strong>英文、數字、底線</strong>，且不能有空格。最後的 <code>值</code> 實際上是選填的，若空著不填，它預設就會是 <code>0</code>（在 <code>int</code> 時），因此若是為了計數，不用特別去輸入任何數值。打完這些後，記得點擊 <code>新增</code> 按鈕，才算建立好變數，建立好後即可關閉變數管理頁面。</p><h2 id="display" tabindex="-1">Display <a class="header-anchor" href="#display" aria-label="Permalink to &quot;Display&quot;">​</a></h2><p>顧名思義，<code>Display</code> 節點就是用來顯示資訊的，有點類似傳統程式語言中的輸出函式。</p><p>這個節點可以設定的東西都很直觀，<code>文字顏色</code> 和 <code>背景顏色</code> 的設定應該不用多說，比賽時若會用到 <code>Display</code>，也不會特別要求這部分。<code>標題</code> 和 <code>內文</code> 的輸入格式就比較特別了，一般的文字要使用 <code>&quot;</code> 來包住，並且在連接變數時，會使用 <code>+</code>；輸入變數或特殊功能文字（如<strong>換行</strong>使用的 <code>newline</code>）則可以使用 <code>內文</code> 旁的鉛筆符號來插入；而連接這些元素的，則是使用 <code>+</code>。</p><p>舉個例子，若我想要輸出變數 <code>a</code>、<code>b</code>、<code>c</code> 的值，並成三行，我就可以把 <code>內文</code> 寫成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;a: &quot; + var_a + newline + &quot;b: &quot; + var_b + newline + &quot;c: &quot; + var_c</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">小提示</p><p>雖然 <code>Display</code> 設定起來自由度很高，不過通常比賽中也只會要求諸如「輸出某個資訊」等，不必過於拘泥形式。</p></div><h2 id="set-變數" tabindex="-1">Set（變數） <a class="header-anchor" href="#set-變數" aria-label="Permalink to &quot;Set（變數）&quot;">​</a></h2><h2 id="if" tabindex="-1">If <a class="header-anchor" href="#if" aria-label="Permalink to &quot;If&quot;">​</a></h2><h2 id="wait-for-變數" tabindex="-1">Wait for（變數） <a class="header-anchor" href="#wait-for-變數" aria-label="Permalink to &quot;Wait for（變數）&quot;">​</a></h2><h2 id="迴圈" tabindex="-1">迴圈 <a class="header-anchor" href="#迴圈" aria-label="Permalink to &quot;迴圈&quot;">​</a></h2><h2 id="pallet" tabindex="-1">Pallet <a class="header-anchor" href="#pallet" aria-label="Permalink to &quot;Pallet&quot;">​</a></h2><h2 id="manual-decision" tabindex="-1">Manual-Decision <a class="header-anchor" href="#manual-decision" aria-label="Permalink to &quot;Manual-Decision&quot;">​</a></h2><h2 id="set-坐標變數化" tabindex="-1">Set（坐標變數化） <a class="header-anchor" href="#set-坐標變數化" aria-label="Permalink to &quot;Set（坐標變數化）&quot;">​</a></h2>',18)])])}const b=a(c,[["render",i]]);export{u as __pageData,b as default};
